import{_ as e,o,c as l,ag as i}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"使用方式","description":"了解 bamdra-openclaw-memory 在真实 OpenClaw 工作流中的使用方式，包括无感恢复与显式工具控制。","frontmatter":{"title":"使用方式","description":"了解 bamdra-openclaw-memory 在真实 OpenClaw 工作流中的使用方式，包括无感恢复与显式工具控制。"},"headers":[],"relativePath":"zh/guide/usage.md","filePath":"zh/guide/usage.md","lastUpdated":null}'),r={name:"zh/guide/usage.md"};function t(c,a,d,h,n,s){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h1><h2 id="正确的使用理解" tabindex="-1">正确的使用理解 <a class="header-anchor" href="#正确的使用理解" aria-label="Permalink to &quot;正确的使用理解&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> 的目标，不是让用户频繁感知“工具被调用”，而是让 OpenClaw 在日常协作里自然具备连续性。在多数场景下，最好的体验是无感的：话题自动接回，稳定事实被持续利用，用户不需要重复背景。</p><h2 id="两种使用模式" tabindex="-1">两种使用模式 <a class="header-anchor" href="#两种使用模式" aria-label="Permalink to &quot;两种使用模式&quot;">​</a></h2><h3 id="_1-无感连续性恢复" tabindex="-1">1. 无感连续性恢复 <a class="header-anchor" href="#_1-无感连续性恢复" aria-label="Permalink to &quot;1. 无感连续性恢复&quot;">​</a></h3><p>这是默认体验。用户只需要像往常一样在 OpenClaw 中工作，而记忆层会负责：</p><ul><li>保留并恢复较早的话题分支</li><li>围绕当前任务装配更紧凑的上下文</li><li>在合适的时候复用之前保存过的稳定事实</li></ul><h3 id="_2-显式运维控制" tabindex="-1">2. 显式运维控制 <a class="header-anchor" href="#_2-显式运维控制" aria-label="Permalink to &quot;2. 显式运维控制&quot;">​</a></h3><p>当流程变得更复杂，或者 operator 需要更强控制时，可以直接调用这些记忆工具：</p><ul><li><code>memory_list_topics</code></li><li><code>memory_switch_topic</code></li><li><code>memory_save_fact</code></li><li><code>memory_compact_topic</code></li><li><code>memory_search</code></li></ul><h2 id="典型使用过程" tabindex="-1">典型使用过程 <a class="header-anchor" href="#典型使用过程" aria-label="Permalink to &quot;典型使用过程&quot;">​</a></h2><h3 id="正常协作中" tabindex="-1">正常协作中 <a class="header-anchor" href="#正常协作中" aria-label="Permalink to &quot;正常协作中&quot;">​</a></h3><p>用户会在规划、执行、跟进之间来回切换。记忆层的职责，是在不打断对话体验的前提下，保住真正重要的分支和事实。</p><h3 id="当一个事实值得长期保存" tabindex="-1">当一个事实值得长期保存 <a class="header-anchor" href="#当一个事实值得长期保存" aria-label="Permalink to &quot;当一个事实值得长期保存&quot;">​</a></h3><p>对于偏好、环境路径、项目约束、决策结果等长期有效的信息，使用 <code>memory_save_fact</code> 保存是最合理的方式。</p><h3 id="当需要更强控制时" tabindex="-1">当需要更强控制时 <a class="header-anchor" href="#当需要更强控制时" aria-label="Permalink to &quot;当需要更强控制时&quot;">​</a></h3><p>如果团队需要有意识地回到某个分支，或者把某条线索单独管理，可以通过 <code>memory_list_topics</code> 和 <code>memory_switch_topic</code> 显式完成。</p><h3 id="当某条分支已经很长" tabindex="-1">当某条分支已经很长 <a class="header-anchor" href="#当某条分支已经很长" aria-label="Permalink to &quot;当某条分支已经很长&quot;">​</a></h3><p>用 <code>memory_compact_topic</code> 刷新摘要，让后续恢复更准确、更清晰。</p><h2 id="日常操作建议" tabindex="-1">日常操作建议 <a class="header-anchor" href="#日常操作建议" aria-label="Permalink to &quot;日常操作建议&quot;">​</a></h2><ul><li>普通连续性恢复优先交给隐式机制</li><li>只保存真正稳定、可复用的事实</li><li>在追问用户前，优先搜索记忆</li><li>让记忆帮助工作，而不是干扰对话体验</li></ul>',21)])])}const _=e(r,[["render",t]]);export{p as __pageData,_ as default};
